  1→import type { ComponentType } from 'react';
  2→
  3→// ---------------------------------------------------------------------------
  4→// SDUI — Server Driven UI Type System
  5→// RFC: .claude/rfc-conteudo-dinamico.txt
  6→// ---------------------------------------------------------------------------
  7→
  8→// ---- 3.4  Context & Interpolation ----------------------------------------
  9→
 10→export type SDUIContextValue =
 11→  | string
 12→  | number
 13→  | boolean
 14→  | null
 15→  | SDUIContext
 16→  | SDUIContextValue[];
 17→
 18→export interface SDUIContext {
 19→  [key: string]: SDUIContextValue;
 20→}
 21→
 22→// ---- 3.5  JSON Logic (subset) --------------------------------------------
 23→
 24→/**
 25→ * Accesses a value from the context using dot notation.
 26→ * @example { var: 'balance.pointsFormatted' }
 27→ */
 28→export interface SDUIVarOperator {
 29→  var: string;
 30→}
 31→
 32→export type SDUILogicPrimitive = string | number | boolean | null;
 33→export type SDUILogicOperand = SDUIVarOperator | SDUILogicPrimitive | SDUIRule;
 34→
 35→export interface SDUIComparisonRule {
 36→  '=='?: [SDUILogicOperand, SDUILogicOperand];
 37→  '!='?: [SDUILogicOperand, SDUILogicOperand];
 38→  '>'?: [SDUILogicOperand, SDUILogicOperand];
 39→  '<'?: [SDUILogicOperand, SDUILogicOperand];
 40→  '>='?: [SDUILogicOperand, SDUILogicOperand];
 41→  '<='?: [SDUILogicOperand, SDUILogicOperand];
 42→}
 43→
 44→export interface SDUILogicalRule {
 45→  and?: SDUIRule[];
 46→  or?: SDUIRule[];
 47→  '!'?: SDUIRule;
 48→}
 49→
 50→export type SDUIRule = SDUIComparisonRule | SDUILogicalRule;
 51→
 52→/**
 53→ * A boolean value computed from a JSON Logic rule.
 54→ * Used for visibility, enabled state, or any boolean prop.
 55→ * @example { rule: { '>': [{ var: 'form.points' }, 0] } }
 56→ */
 57→export interface SDUIConditional {
 58→  rule: SDUIRule;
 59→}
 60→
 61→export interface SDUIValidationRule {
 62→  rule: SDUIRule;
 63→  message: string;
 64→}
 65→
 66→export interface SDUIValidation {
 67→  rules: SDUIValidationRule[];
 68→}
 69→
 70→// ---- 3.3  Rich Text -------------------------------------------------------
 71→
 72→export interface SDUITextNode {
 73→  type: 'text';
 74→  value: string;
 75→  bold?: boolean;
 76→  italic?: boolean;
 77→  color?: string;
 78→}
 79→
 80→export interface SDUILinkNode {
 81→  type: 'link';
 82→  text: string;
 83→  to: string;
 84→  trackEvent?: string;
 85→}
 86→
 87→export interface SDUIIconNode {
 88→  type: 'icon';
 89→  name: string;
 90→  color?: string;
 91→  size?: number;
 92→}
 93→
 94→export interface SDUILineBreakNode {
 95→  type: 'br';
 96→}
 97→
 98→export type SDUIRichTextChild =
 99→  | SDUITextNode
100→  | SDUILinkNode
101→  | SDUIIconNode
102→  | SDUILineBreakNode;
103→
104→export interface SDUIRichText {
105→  type: 'rich_text';
106→  children: SDUIRichTextChild[];
107→}
108→
109→// ---- 3.2  Components ------------------------------------------------------
110→
111→export type SDUIPropValue =
112→  | string
113→  | number
114→  | boolean
115→  | null
116→  | SDUIConditional
117→  | SDUIValidation
118→  | SDUIRichText
119→  | SDUIPropValue[]
120→  | { [key: string]: SDUIPropValue };
121→
122→export interface SDUIComponentProps {
123→  [key: string]: SDUIPropValue;
124→}
125→
126→export interface SDUIComponent<T extends string = string> {
127→  type: T;
128→  props: SDUIComponentProps;
129→  visible?: SDUIConditional;
130→}
131→
132→// ---- 3.1  Screen Structure ------------------------------------------------
133→
134→export type SDUIHeader = SDUIComponent;
135→export type SDUIFooter = SDUIComponent;
136→
137→export interface SDUIScreen {
138→  id: string;
139→  context: SDUIContext;
140→  header?: SDUIHeader;
141→  body: SDUIComponent[];
142→  footer?: SDUIFooter;
143→}
144→
145→export interface SDUIScreenResponse {
146→  screen: SDUIScreen;
147→}
148→
149→// ---- Component Registry ---------------------------------------------------
150→
151→export type SDUIComponentRenderer<P extends SDUIComponentProps = SDUIComponentProps> =
152→  ComponentType<{
153→    props: P;
154→    context: SDUIContext;
155→  }>;
156→
157→export interface SDUIComponentRegistry {
158→  [type: string]: SDUIComponentRenderer;
159→}
160→
