173→  'icon_text_row',
174→  'section_heading',
175→  'nav_header',
176→  'rich_text',
177→  'voucher_card',
178→  'empty_state',
179→] as const;
180→
181→export type SDUIKnownType = (typeof SDUI_KNOWN_TYPES)[number];
